--- route.c.old Thu May 17 02:14:03 2001
+++ route.c     Sun Jun  3 11:18:07 2001
@@ -425,7 +425,7 @@
        if (ifa == 0)
                ifa = ifa_ifwithnet(gateway);
        if (ifa == 0) {
-               struct rtentry *rt = rtalloc1(dst, 0, 0UL);
+               struct rtentry *rt = rtalloc1(gateway, 0, 0UL);
                if (rt == 0)
                        return (0);
                rt->rt_refcnt--;
